package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.validation.PatientValidator;import org.junit.jupiter.api.*;import org.mockito.*;import java.sql.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;
class PatientServiceImplTest{@Mock PatientDao p;@Mock UserDao u;@Mock RoleDao r;@Mock AuditLogDao a;@Mock Connection c;AutoCloseable m;PatientServiceImpl s;@BeforeEach void init()throws Exception{m=MockitoAnnotations.openMocks(this);when(c.getAutoCommit()).thenReturn(true);s=new PatientServiceImpl(p,u,r,new PatientValidator(),a,()->c,()->"PAT-2026-000001");}@AfterEach void close()throws Exception{m.close();}@Test void createWithoutLoginCommits()throws Exception{when(p.createPatientRecord(eq(c),any())).thenReturn(4L);ServiceResult<Long>x=s.createPatient(f(),ctx());assertTrue(x.isSuccess());verify(c).commit();verify(u,never()).create(any(),any());}@Test void createWithLoginIsAtomic()throws Exception{PatientForm f=f();login(f);when(r.findRoleIdByName("PATIENT")).thenReturn(Optional.of(2L));when(u.create(eq(c),any())).thenReturn(3L);when(p.createPatientRecord(eq(c),any())).thenReturn(4L);assertTrue(s.createPatient(f,ctx()).isSuccess());verify(a).recordEvent(eq("PATIENT_LOGIN_ACCOUNT_CREATED"),anyLong(),eq("PATIENT"),eq(4L),any(),any());}@Test void patientInsertFailureRollsBack()throws Exception{PatientForm f=f();login(f);when(r.findRoleIdByName("PATIENT")).thenReturn(Optional.of(2L));when(u.create(eq(c),any())).thenReturn(3L);when(p.createPatientRecord(eq(c),any())).thenThrow(new SQLException());assertEquals(ServiceResult.Status.SYSTEM_ERROR,s.createPatient(f,ctx()).getStatus());verify(c).rollback();}@Test void duplicatePatientNumber()throws Exception{when(p.existsByPatientNumber(any())).thenReturn(true);assertEquals(ServiceResult.Status.DUPLICATE,s.createPatient(f(),ctx()).getStatus());}@Test void activationLockedIsBlocked()throws Exception{Patient x=patient();x.setUserStatus("LOCKED");when(p.findById(4L)).thenReturn(Optional.of(x));assertEquals(ServiceResult.Status.CONFLICT,s.activatePatient(4L,ctx()).getStatus());}@Test void deactivationBlockersAudit()throws Exception{when(p.findById(4L)).thenReturn(Optional.of(patient()));when(p.hasFutureAppointments(4L)).thenReturn(true);assertEquals(ServiceResult.Status.CONFLICT,s.deactivatePatient(4L,ctx()).getStatus());verify(a).recordEvent(eq("PATIENT_DEACTIVATION_BLOCKED"),anyLong(),eq("PATIENT"),eq(4L),any(),any());}private PatientForm f(){PatientForm f=new PatientForm();f.setFirstName("Demo");f.setLastName("Patient");f.setDateOfBirth("1990-01-01");f.setGender("OTHER");f.setBloodGroup("O+");f.setPhone("9000000002");f.setStatus("ACTIVE");return f;}private void login(PatientForm f){f.setCreateLoginAccount(true);f.setEmail("p@example.com");f.setUsername("patient1");f.setPassword("Strong@123");f.setConfirmPassword("Strong@123");}private Patient patient(){Patient p=new Patient();p.setPatientId(4L);p.setUserId(3L);return p;}private AuditContext ctx(){return new AuditContext(1L,"ip","ua");}}
